<?php

/**
 * ApFormElementsTable
 * 
 * This class has been auto-generated by the Doctrine ORM Framework
 */
class ApFormElementsTable extends Doctrine_Table
{
    /**
     * Returns an instance of this class.
     *
     * @return ApFormElementsTable The table instance
     */
    public static function getInstance()
    {
        return Doctrine_Core::getTable('ApFormElements');
    }
	   //OTB Start Patch - For Implementing Finance Bills
	public function getAllFields($formId, $element_type=False)
	{
		$q=$this->createQuery('e')
			->select('e.element_id,e.element_title')
			->where('e.form_id = ?',$formId)
			->andWhere('e.element_status = ?',1);
		if($element_type){
			$q->andWhere('e.element_type = ?', $element_type);
		}else{
			$q->andWhereNotIn('e.element_type',array('email','section','page_break','file'));
		}
		$elements= $q->execute();
		$element_ids=array();
		$titles=array();
		foreach($elements as $key => $element){
			if($key == 0){
				$element_ids[]='';
				$titles[]='';
			}
			$element_ids[]=$element['element_id'];
			$titles[]=$element['element_title'];
		}
		return array_combine($element_ids,$titles);
	}
	   //OTB End Patch - For Implementing Finance Bills
	//OTB get element type
	public function getElementsType($form_id,$element_id)
	{
		$q=$this->createQuery('e')
			->select('e.element_type')
			->where('e.form_id =? AND e.element_id =?',array($form_id,$element_id));
		$element=$q->fetchOne();
		return $element->getElementType();
			
	}
	public function getAllFormFieldsIncludeEmail($formId)
	{
		$q=$this->createQuery('e')
			->select('e.element_id,e.element_title')
			->where('e.form_id = ?',$formId)
			->andWhere('e.element_status = ?',1)
			->andWhereNotIn('e.element_type',array('section','page_break','file'));
		$elements= $q->execute();
		foreach($elements as $key => $element){
			if($key == 0){
				$element_ids[]='';
				$titles[]='';
			}
			$element_ids[]='element_'.$element['element_id'];
			$titles[]=$element['element_title'];
		}
		return array_combine($element_ids,$titles);
	}
}